#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        static char A[100005];
        static char B[100005];
        scanf("%s", A);
        scanf("%s", B);
        int n = strlen(A);
        int ans = 0;
        int inOdd = 0, inEven = 0;
        for (int i = 0; i < n; ++i) {
            int diff = (A[i] != B[i]);
            if (i % 2 == 0) { // 0‑based index: even -> 1‑based odd position
                if (diff) {
                    if (!inOdd) { ans++; inOdd = 1; }
                } else {
                    inOdd = 0;
                }
            } else { // 0‑based odd -> 1‑based even position
                if (diff) {
                    if (!inEven) { ans++; inEven = 1; }
                } else {
                    inEven = 0;
                }
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

