#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().splitlines()
    t = int(data[0])
    idx = 1
    out = []
    for _ in range(t):
        A = data[idx].strip(); idx += 1
        B = data[idx].strip(); idx += 1
        ans = 0
        in_odd = False
        in_even = False
        for i, (a, b) in enumerate(zip(A, B)):
            diff = a != b
            if i % 2 == 0:  # 1‑based odd
                if diff:
                    if not in_odd:
                        ans += 1
                        in_odd = True
                else:
                    in_odd = False
            else:           # 1‑based even
                if diff:
                    if not in_even:
                        ans += 1
                        in_even = True
                else:
                    in_even = False
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

